parameters.jsCode:
const airtable = $json ?? {};
const odoo = $('Normalize Odoo Delivery').first().json ?? {};
const errors = [];

if (airtable.workflowRevision !== 'WL-ATTACHMENTS-V5.5.2') {
  errors.push(`Unexpected Airtable workflow revision: ${airtable.workflowRevision ?? 'MISSING'}`);
}
if (odoo.workflowRevision !== 'WL-ATTACHMENTS-V5.5.2') {
  errors.push(`Unexpected Odoo workflow revision: ${odoo.workflowRevision ?? 'MISSING'}`);
}
if (airtable.airtableStatus !== 'success' || !airtable.airtableRecordId) {
  errors.push(`Airtable write failed: ${airtable.airtableError ?? 'record ID missing'}`);
}
if (airtable.airtableNativeAttachmentCount !== airtable.expectedAttachmentCount) {
  errors.push(`Airtable native attachment count mismatch: expected ${airtable.expectedAttachmentCount}, received ${airtable.airtableNativeAttachmentCount ?? 'UNKNOWN'}`);
}
if (odoo.odooStatus !== 'success' || !odoo.odooWebLeadId) {
  const httpLabel = odoo.odooHttpStatus ?? 'not exposed';
  const responseLabel = odoo.odooResponseReceived ? 'response body received' : 'no response body';
  errors.push(`Odoo delivery failed (HTTP ${httpLabel}; ${responseLabel}): ${odoo.odooError ?? 'web_lead_id missing'}`);
}

if (errors.length) {
  throw new Error(`WL-ATTACHMENTS-V5.5.2 final production gate failed: ${errors.join(' | ')}`);
}

return {
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.5.2',
    status: 'success',
    leadId: airtable.leadId,
    airtableRecordId: airtable.airtableRecordId,
    airtableNativeAttachmentCount: airtable.airtableNativeAttachmentCount,
    odooStatus: odoo.odooStatus,
    odooHttpStatus: odoo.odooHttpStatus,
    odooWebLeadId: odoo.odooWebLeadId,
    odooLeadId: odoo.odooLeadId,
    odooDecision: odoo.odooDecision,
    odooState: odoo.odooState,
  },
};

const body = $('Webhook').first().json.body ?? {};
const rawFiles = body.UploadPhotosOfYourScrapUpTo10;

if (!Array.isArray(rawFiles)) {
  throw new Error('Cognito attachment field UploadPhotosOfYourScrapUpTo10 is not an array.');
}
if (rawFiles.length === 0) {
  throw new Error('Cognito submission contains no attachments.');
}
if (rawFiles.length > 10) {
  throw new Error(`Cognito submission contains ${rawFiles.length} attachments; maximum supported is 10.`);
}

const seen = new Set();
const expectedAttachmentCount = rawFiles.length;
const entryNumber = body.Entry?.Number;
if (!entryNumber) {
  throw new Error('Cognito submission is missing Entry.Number.');
}
const leadId = `WL${entryNumber}`;

return rawFiles.map((file, attachmentIndex) => {
  if (!file || typeof file !== 'object') {
    throw new Error(`Attachment ${attachmentIndex + 1} is not a valid file object.`);
  }

  const originalFileName = String(file.Name ?? '').trim();
  const sourceDownloadUrl = String(file.File ?? '').trim();
  const sourceFileId = String(file.Id ?? '').trim();
  const contentType = String(file.ContentType ?? '').trim();
  const sizeBytes = Number(file.Size ?? 0);

  if (!sourceFileId) {
    throw new Error(`Attachment ${attachmentIndex + 1} is missing its Cognito file ID.`);
  }
  if (!originalFileName) {
    throw new Error(`Attachment ${attachmentIndex + 1} is missing its original filename.`);
  }
  if (!sourceDownloadUrl || !sourceDownloadUrl.startsWith('https://')) {
    throw new Error(`Attachment ${attachmentIndex + 1} (${originalFileName}) has an invalid download URL.`);
  }
  if (!contentType) {
    throw new Error(`Attachment ${attachmentIndex + 1} (${originalFileName}) is missing ContentType.`);
  }
  if (!Number.isInteger(sizeBytes) || sizeBytes <= 0) {
    throw new Error(`Attachment ${attachmentIndex + 1} (${originalFileName}) has an invalid size.`);
  }
  if (seen.has(sourceFileId)) {
    throw new Error(`Duplicate Cognito source file ID detected: ${sourceFileId}.`);
  }
  seen.add(sourceFileId);

  return {
    json: {
      workflowRevision: 'WL-ATTACHMENTS-V5.5.2',
      leadId,
      expectedAttachmentCount,
      attachmentIndex,
      sourceFileId,
      storageIdentity: sourceFileId,
      originalFileName,
      contentType,
      sizeBytes,
      sourceDownloadUrl,
    },
    pairedItem: { item: 0 },
  };
});

const input = $input.item;
const meta = input.json ?? {};
const binaryData = input.binary?.data;

if (!meta.sourceFileId || !meta.originalFileName || !meta.contentType) {
  throw new Error('Canonical attachment metadata is incomplete before binary restoration.');
}
if (!binaryData) {
  throw new Error(`Downloaded binary data is missing for ${meta.originalFileName}.`);
}
if (Number(binaryData.bytes ?? 0) !== Number(meta.sizeBytes)) {
  throw new Error(`Downloaded byte count mismatch for ${meta.originalFileName}: expected ${meta.sizeBytes}, received ${binaryData.bytes ?? 'UNKNOWN'}.`);
}

return {
  json: { ...meta },
  binary: {
    ...(input.binary ?? {}),
    data: {
      ...binaryData,
      fileName: meta.originalFileName,
      mimeType: meta.contentType,
    },
  },
  pairedItem: input.pairedItem ?? { item: $itemIndex },
};

