parameters.jsCode:
const joined = $json ?? {};
const source = $('Restore Original Filename').item.json;

if (!source || joined.sourceFileId !== source.sourceFileId) {
  throw new Error(`Current loop source mismatch: joined=${joined.sourceFileId ?? 'UNKNOWN'}, source=${source?.sourceFileId ?? 'UNKNOWN'}.`);
}
if (joined.uploadStatus !== 'success' || !joined.driveFileId) {
  throw new Error(`Attachment upload is incomplete for ${source.originalFileName}.`);
}
if (!['success', 'failed', 'unsupported'].includes(joined.analysisStatus)) {
  throw new Error(`Attachment ${source.originalFileName} has an invalid analysis status.`);
}
if (joined.driveFileName !== source.originalFileName) {
  throw new Error(`Attachment filename changed after upload: ${source.originalFileName} -> ${joined.driveFileName}.`);
}
if (joined.driveMimeType !== source.contentType) {
  throw new Error(`Attachment MIME changed after upload for ${source.originalFileName}.`);
}

return {
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.5.2',
    leadId: source.leadId,
    expectedAttachmentCount: source.expectedAttachmentCount,
    attachmentIndex: source.attachmentIndex,
    sourceFileId: source.sourceFileId,
    originalFileName: source.originalFileName,
    contentType: source.contentType,
    sizeBytes: source.sizeBytes,
    sourceDownloadUrl: source.sourceDownloadUrl,
    driveFileId: joined.driveFileId,
    driveFileName: joined.driveFileName,
    driveMimeType: joined.driveMimeType,
    driveSizeBytes: joined.driveSizeBytes,
    driveViewUrl: joined.driveViewUrl,
    driveDownloadUrl: joined.driveDownloadUrl,
    driveShared: joined.driveShared,
    uploadStatus: joined.uploadStatus,
    analysisType: joined.analysisType,
    analysisStatus: joined.analysisStatus,
    analysisData: joined.analysisData,
    analysisText: joined.analysisText,
    analysisError: joined.analysisError,
    airtableAttachment: {
      url: joined.driveDownloadUrl,
      filename: source.originalFileName,
    },
  },
};

const rows = Array.isArray($json.data) ? $json.data : [];
const rawFiles = $('Webhook').first().json.body?.UploadPhotosOfYourScrapUpTo10;
const expectedAttachmentCount = Array.isArray(rawFiles) ? rawFiles.length : 0;

if (rows.length !== expectedAttachmentCount) {
  throw new Error(`Attachment completeness check failed: expected ${expectedAttachmentCount}, received ${rows.length}.`);
}

const ordered = [...rows].sort((a, b) => a.attachmentIndex - b.attachmentIndex);
const sourceIds = new Set();
const driveIds = new Set();
const indexes = new Set();

for (let expectedIndex = 0; expectedIndex < ordered.length; expectedIndex++) {
  const row = ordered[expectedIndex];
  if (row.workflowRevision !== 'WL-ATTACHMENTS-V5.5.2') throw new Error(`Revision marker missing for ${row.originalFileName ?? 'UNKNOWN'}.`);
  if (row.attachmentIndex !== expectedIndex) throw new Error(`Attachment indexes are not contiguous at position ${expectedIndex}.`);
  if (!row.sourceFileId || sourceIds.has(row.sourceFileId)) throw new Error(`Missing or duplicate sourceFileId: ${row.sourceFileId ?? 'UNKNOWN'}.`);
  if (!row.sourceDownloadUrl || !String(row.sourceDownloadUrl).startsWith('https://')) throw new Error(`Missing source download URL for ${row.originalFileName}.`);
  if (!row.driveFileId || driveIds.has(row.driveFileId)) throw new Error(`Missing or duplicate Drive file ID for ${row.originalFileName}.`);
  if (indexes.has(row.attachmentIndex)) throw new Error(`Duplicate attachment index: ${row.attachmentIndex}.`);
  if (row.uploadStatus !== 'success') throw new Error(`Upload failed for ${row.originalFileName}.`);
  if (!row.airtableAttachment?.url || row.airtableAttachment.filename !== row.originalFileName) throw new Error(`Invalid Airtable attachment object for ${row.originalFileName}.`);
  if (!['success', 'failed', 'unsupported'].includes(row.analysisStatus)) throw new Error(`Missing or invalid analysis status for ${row.originalFileName}.`);
  if (row.analysisStatus === 'failed' && !row.analysisError?.message) throw new Error(`Failed analysis is missing an error message for ${row.originalFileName}.`);
  sourceIds.add(row.sourceFileId);
  driveIds.add(row.driveFileId);
  indexes.add(row.attachmentIndex);
}

const successfulAnalysisCount = ordered.filter((row) => row.analysisStatus === 'success').length;
const failedAnalysisCount = ordered.filter((row) => row.analysisStatus === 'failed').length;
const unsupportedAnalysisCount = ordered.filter((row) => row.analysisStatus === 'unsupported').length;
const imageAttachmentCount = ordered.filter((row) => String(row.contentType).startsWith('image/')).length;
const pdfAttachmentCount = ordered.filter((row) => row.contentType === 'application/pdf').length;

return [{
  json: {
    workflowRevision: 'WL-ATTACHMENTS-V5.5.2',
    expectedAttachmentCount,
    imageAttachmentCount,
    pdfAttachmentCount,
    successfulAttachmentCount: ordered.length,
    successfulUploadCount: ordered.filter((row) => row.uploadStatus === 'success').length,
    successfulAnalysisCount,
    failedAnalysisCount,
    unsupportedAnalysisCount,
    attachmentAnalysis: ordered.map((row) => ({
      attachment_index: row.attachmentIndex,
      source_file_id: row.sourceFileId,
      filename: row.originalFileName,
      content_type: row.contentType,
      analysis_type: row.analysisType,
      analysis_status: row.analysisStatus,
      analysis_data: row.analysisData,
      analysis_text: row.analysisText,
      analysis_error: row.analysisError,
    })),
    airtableAttachments: ordered.map((row) => row.airtableAttachment),
    analysisWarnings: ordered.filter((row) => row.analysisStatus === 'failed').map((row) => ({ filename: row.originalFileName, error: row.analysisError?.message ?? 'UNKNOWN ERROR' })),
    attachmentManifest: ordered.map((row) => ({
      attachmentIndex: row.attachmentIndex,
      sourceFileId: row.sourceFileId,
      originalFileName: row.originalFileName,
      contentType: row.contentType,
      sizeBytes: row.sizeBytes,
      sourceDownloadUrl: row.sourceDownloadUrl,
      driveFileId: row.driveFileId,
      driveViewUrl: row.driveViewUrl,
      uploadStatus: row.uploadStatus,
      analysisStatus: row.analysisStatus,
    })),
  },
}];

const meta = $('Restore Original Filename').item.json;
const uploaded = $json ?? {};
const driveFileId = String(uploaded.id ?? '').trim();
const driveFileName = String(uploaded.name ?? '').trim();
const driveMimeType = String(uploaded.mimeType ?? '').trim();
const driveSizeBytes = Number(uploaded.size ?? 0);

if (!driveFileId) throw new Error(`Google Drive returned no file ID for ${meta.originalFileName}.`);
if (driveFileName !== meta.originalFileName) {
  throw new Error(`Drive filename mismatch for ${meta.sourceFileId}: expected "${meta.originalFileName}", received "${driveFileName}".`);
}
if (driveMimeType !== meta.contentType) {
  throw new Error(`Drive MIME mismatch for ${meta.originalFileName}: expected ${meta.contentType}, received ${driveMimeType}.`);
}
if (driveSizeBytes !== Number(meta.sizeBytes)) {
  throw new Error(`Drive size mismatch for ${meta.originalFileName}: expected ${meta.sizeBytes}, received ${uploaded.size ?? 'UNKNOWN'}.`);
}

return {
  json: {
    sourceFileId: meta.sourceFileId,
    driveFileId,
    driveFileName,
    driveMimeType,
    driveSizeBytes,
    driveViewUrl: uploaded.webViewLink || `https://drive.google.com/file/d/${driveFileId}/view`,
